/*
 * floor() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly floor  (test_floor_opt.elf)
 *   2. Linked with toolchain's default floor        (test_floor_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += floor(vx);
#else
    double r = floor(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    emit_u(0xfff0000000000000ULL);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074, rounds to 0.0 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal, rounds to -1.0 */
    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (4) --- */
    emit(DBL_MIN);                  /* 2^-1022, smallest normal positive, rounds to 0.0 */
    emit(-DBL_MIN);                 /* smallest normal negative, rounds to -1.0 */
    emit_u(0x7fefffffffffffffULL);  /* DBL_MAX: large exact integer */
    emit_u(0xffefffffffffffffULL);  /* -DBL_MAX */

    /* --- Section 4: ULP neighbors of 1.0 and 2.0 (8) --- */
    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0: 0.9999999999999998 */
    emit(1.0);
    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0: 1.0000000000000002 */
    emit_u(0x3feffff000000000ULL);  /* a few ULPs below 1.0 */
    emit(-1.0);
    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0 */
    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0 */
    emit_u(0x4000000000000000ULL);  /* exactly 2.0 */

    /* --- Section 5: Half-integer values n+0.5 for n=0..5 and negatives (12) --- */
    emit(0.5);
    emit(1.5);
    emit(2.5);
    emit(3.5);
    emit(4.5);
    emit(5.5);
    emit(-0.5);
    emit(-1.5);
    emit(-2.5);
    emit(-3.5);
    emit(-4.5);
    emit(-5.5);

    /* --- Section 6: Near-integer boundary bit patterns (10) --- */
    emit_u(0x3fdffffffffffffeULL);  /* just below 0.5 */
    emit_u(0x3fe0000000000001ULL);  /* just above 0.5 */
    emit_u(0xbfdffffffffffffeULL);  /* just above -0.5 (toward zero) */
    emit_u(0xbfe0000000000001ULL);  /* just below -0.5 (away from zero) */
    emit_u(0x3ff7ffffffffffffULL);  /* just below 1.5 */
    emit_u(0x3ff8000000000001ULL);  /* just above 1.5 */
    emit_u(0xbff7ffffffffffffULL);  /* just above -1.5 (toward zero) */
    emit_u(0xbff8000000000001ULL);  /* just below -1.5 (away from zero) */
    emit_u(0x4003ffffffffffffULL);  /* just below 2.5 */
    emit_u(0x4004000000000001ULL);  /* just above 2.5 */

    /* --- Section 7: 2^52 integer-precision boundary (8) --- */
    /* At 2^52, adjacent doubles differ by 1.0: floor is identity for integers */
    emit_u(0x4330000000000000ULL);  /* 2^52 exactly = 4503599627370496.0 */
    emit_u(0x432fffffffffffffULL);  /* one ULP below 2^52: last double with fraction */
    emit_u(0x4330000000000001ULL);  /* one ULP above 2^52: all integers here */
    emit_u(0x4340000000000000ULL);  /* 2^53: all representable values are integers */
    emit_u(0x4350000000000000ULL);  /* 2^54 */
    emit_u(0xc330000000000000ULL);  /* -2^52 */
    emit_u(0xc32fffffffffffffULL);  /* one ULP toward zero from -2^52 */
    emit_u(0xc330000000000001ULL);  /* one ULP away from zero from -2^52 */

    /* --- Section 8: Negative fractional values (10) --- */
    /* floor rounds toward -Inf, so negatives with fractions go more negative */
    emit(-0.1);
    emit(-0.4);
    emit(-0.6);
    emit(-0.9);
    emit(-1.1);
    emit(-1.9);
    emit(-2.1);
    emit(-10.5);
    emit(-100.9);
    emit(-1000.1);

    /* --- Section 9: Mid-range positive fractional values (8) --- */
    emit(0.1);
    emit(0.4);
    emit(0.6);
    emit(0.9);
    emit(1.1);
    emit(10.7);
    emit(100.5);
    emit(1000.9);

    /* --- Section 10: Large values and large integer-exact floats (8) --- */
    emit(1.0e15);                   /* large but has fractional ULP spacing */
    emit(-1.0e15);
    emit(1.0e16);                   /* near 2^53: integers only */
    emit(-1.0e16);
    emit(1.0e100);                  /* very large, integer-valued */
    emit(-1.0e100);
    emit(1.0e300);
    emit(-1.0e300);

    /* --- Section 11: Power-of-2 exponent switching points (19) --- */
    emit(0.25);                     /* 2^-2 */
    emit(0.125);                    /* 2^-3 */
    emit_u(0x3fc0000000000000ULL);  /* 0.125 = 2^-3 exact */
    emit(4.0);
    emit(8.0);
    emit(16.0);
    emit(32.0);
    emit(64.0);
    emit(128.0);
    emit(-4.0);
    emit(-8.0);
    emit(-16.0);
    emit(-32.0);
    emit(-64.0);
    emit(-128.0);
    emit_u(0x4010000000000000ULL);  /* 4.0 exact via bits */
    emit_u(0x4020000000000000ULL);  /* 8.0 exact via bits */
    emit_u(0xc010000000000000ULL);  /* -4.0 exact via bits */
    emit_u(0xc020000000000000ULL);  /* -8.0 exact via bits */
}

/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* 7. Sweep [0, 10] in 100 steps and [-10, 0] in 100 steps */
static void test_sweep(void)
{
    double hi = 10.0;
    int nsteps = 100;
    double step = hi / (double)nsteps;

    /* [0, 10] */
    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);

    /* [-10, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (double)i * step);
}

/* 8. Sample [0, 10] every ~0.05 (200 points) */
static void test_exhaustive_small(void)
{
    double hi = 10.0;
    int nsteps = 200;
    double step = hi / (double)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}
